INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Corrigir Músculos Abdominais Desiguais', 'Geral', 'Geral', 'Geral', '/assets/exercises/corrigir-musculos-abdominais-desiguais-wikihow.jpg', ARRAY['Inclua exercícios aeróbicos na rotina para se livrar da gordura abdominal.', 'Faça abdominais e flexões com moderação para não dar tanta ênfase aos abdominais superiores.', 'Faça pranchas focadas em um lado por vez, como as laterais ou as de moinho.', 'Faça o supino unilateral para isolar os músculos.', 'Faça a elevação frontal no cabo ou o remo unilateral para trabalhar ambos os lados do torso.', 'Carregue um peso em um braço enquanto caminha como se fosse uma maleta.', 'Olhe-se no espelho para ver se os seus gominhos são intercalados.', 'Confira se os músculos inferiores parecem estufados.', 'Faça um alongamento frontal para observar se você tem alguma curvatura na coluna vertebral.', 'Analise as suas rotinas atléticas e de exercícios para saber se estão mais focadas em um lado.', 'Se você tende a encurvar a coluna, pratique mantê-la sempre reta.', 'Fortaleça os músculos dorsais e abdominais para ajudar a melhorar a sua postura.', 'Massageie os ombros para corrigir a tensão e a irregularidade muscular.', 'Visite um quiroprata se estiver com dificuldades para melhorar a sua postura.']);
