INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Encher uma Bola de Exercício', 'Geral', 'Geral', 'Geral', '/assets/exercises/encher-uma-bola-de-exercicio-wikihow.jpg', ARRAY['Deixe-a à temperatura ambiente por duas horas.', 'Enfie a ponta da bomba de ar na respectiva entrada da bola.', 'Encha-a até chegar em 80% de sua capacidade.', 'Encha a bola até chegar em seu diâmetro completo.', 'Insira a tampa e deixe-a repousar por mais um dia.', 'Meça o diâmetro da bola.', 'Sente-se em sua bola suíça.', 'Quique em sua bola suíça lentamente.', 'Sente-se sobre ela com as pernas abertas.', 'Tire a tampa e quique lentamente até esvaziá-la por completo.', 'Dobre-a ao guardá-la.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Entrar em Forma ao Estilo Militar', 'Geral', 'Geral', 'Geral', '/assets/exercises/entrar-em-forma-ao-estilo-militar-wikihow.jpg', ARRAY['Entenda os conceitos básicos da forma física.', 'Entenda que as Forças Especiais têm há anos feito uso de exercícios com o peso do corpo com excelentes resultados.', 'Entenda que o alongamento traz melhorias no desempenho, diminui a probabilidade de lesões e aumenta o fluxo sanguíneo e a agilidade.', 'Dentre os alongamentos dinâmicos que devem ser usados antes do treino, incluem-se:', 'Basta fazer esses alongamentos durante dois segundos cada.', 'É importante fazer o seu aquecimento.', 'Treine para melhorar a resistência.', '"Ah, eu faço 50 flexões, como poderia ganhar força assim?', 'A nutrição adequada é necessária para desenvolver e manter uma forma física saudável.', ', carnes magras, frutas e vegetais e beba bastante água.', 'Lembre-se de que atividades cardiovasculares (aeróbicas) intensas que elevem a respiração e a frequência cardíaca a Falhou a verificação gramatical (Erro de conversão.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer Agachamento', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-agachamento-wikihow.jpg', ARRAY['Firme os pés no chão, inclinados um pouco para fora.', 'Coloque a barra atrás da cabeça, com o peso apoiado na parte de trás dos ombros.', 'Dobre os joelhos e abaixe lentamente os quadris, como se estivesse sentando em uma cadeira invisível.', 'Leve os quadris um pouco para frente (sem empinar o bumbum) conforme os abaixa até alcançar os joelhos.', 'Levante o corpo, erguendo os quadris e levando-os para frente enquanto retorna à posição inicial.', 'Nunca curve as costas.', 'Apoie o peso nos calcanhares, não nos dedos.', 'Mantenha os joelhos posicionados.', 'Não coloque a barra na base do pescoço.', 'Inspire ao agachar e expire ao levantar.', 'Aqueça-se para prevenir lesões e aproveitar ao máximo a força do corpo', 'Não utilize um cinto de levantamento de peso ao aprender o agachamento.', 'Faça um agachamento sem pesos para se aquecer ou fortalecer os músculos de modo mais seguro.', 'Faça agachamentos com halteres pequenos para fortalecer os músculos enquanto não consegue fazer os agachamentos tradicionais com barras.', 'Faça um agachamento plié.', 'Experimente um agachamento frontal para trabalhar outros grupos musculares.', 'Experimente um agachamento com os braços elevados para realmente fortalecer os músculos.', 'Mantendo a mesma posição na parte superior do corpo, abra as pernas.', 'Abaixe um pouco a barra nos ombros para trabalhar outros grupos musculares.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Criar um Conjunto de Pesos Caseiro', 'Geral', 'Geral', 'Geral', '/assets/exercises/criar-um-conjunto-de-pesos-caseiro-wikihow.jpg', ARRAY['Use um galão de leite.', 'Use latas de alimentos.', 'Faça pesos de academia a partir de garrafas plásticas.', 'Crie pesos para os punhos com garrafas plásticas.', 'Crie uma bola de ginástica a partir de uma bola de basquete.', 'Use meias para fazer pesos de punho.', 'Use sacos de arroz ou de feijão como mini pesos.', 'Faça pesinhos com uma câmara de pneu de bicicleta.', 'Crie um colete de peso.', 'Use latas de tinta.', 'Use baldes de 20 L.', 'Faça uma barra de peso com garrafas plásticas.', 'Use pneus velhos que tiver em casa.', 'Faça um slosh pipe.', 'Crie um saco de areia a partir de uma bolsa de academia.', 'Use um galão de leite ou de suco.', 'Use corda e pesos de academia comuns.', 'Crie um kettlebell a partir de um saco de batatas.', 'Use um cano de PVC e bolas de basquete antigas para criar um kettlebell.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer os Peitorais Mexerem', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-os-peitorais-mexerem-wikihow.jpg', ARRAY['Concentre-se em exercícios que aumentam a circulação sanguínea no peito.', 'Use o espelho a seu favor.', 'Contraia seus músculos peitorais.', 'Tente trabalhar com cada peitoral isoladamente.', 'Trabalhe na manutenção dos seus peitorais.', 'Comece a malhar seu peito regularmente.', 'Dedique-se a fazer supino com barra', 'De longe, a melhor maneira de construir massa muscular no peito é fazendo supino com halteres.', 'Faça um treino que trabalhe o corpo inteiro em menos de 5 minutos.', 'Siga uma dieta rica em proteína magra e pobre em gordura']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer uma Elevação de Perna em Suspensão', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-uma-elevacao-de-perna-em-suspensao-wikihow.jpg', ARRAY['Segure a barra com as mãos afastadas na largura dos ombros.', 'Mantenha as pernas retas e os pés juntos.', 'Aperte o tronco enquanto você levanta as pernas, mantendo os joelhos retos.', 'Pare de levantar as pernas quando as coxas e os pés estiverem acima dos quadris.', 'Abaixe as pernas lentamente de volta à posição inicial.', 'Trabalhe até chegar a 3 séries de 15 repetições.', 'Modifique a elevação de perna suspensa dobrando os joelhos.', 'Faça elevações de pernas deitado se você não tiver uma barra de elevação do queixo.', 'Tente fazer elevações de joelho se as elevações de perna forem muito desafiadoras.', 'Coloque pesos nos tornozelos para aumentar a intensidade da elevação das pernas em suspensão.', 'Faça um abdominal suspenso para outra forma de fortalecer seu núcleo.', 'Faça torções suspensas para um exercício desafiador para o abdome.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Malhar o Antebraço', 'Geral', 'Geral', 'Geral', '/assets/exercises/malhar-o-antebraco-wikihow.jpg', ARRAY['Use ou crie uma polia.', 'Comece com um peso, depois aumente gradualmente.', 'Segure a polia à frente do corpo.', 'Gire a barra.', 'Gire o peso para fazê-lo retornar à posição inicial.', 'Suspenda um peso de academia ou um kettlebell em cada mão.', 'Fique ereto.', 'Comece a andar.', 'Sente-se na borda de um banco de academia.', 'Comece a levantar um halter de mão ou um kettlebell com cada mão.', 'Apoie o cotovelo na coxa e deixe o braço relaxado.', 'Levante o peso movendo apenas os punhos para cima, na sua direção.', 'Realize de 12 a 15 repetições.', 'Sente-se apoiando os braços em um banco reto de exercícios.', 'Levante a barra com ambas mãos.', 'Abaixe os punhos.', 'Use os punhos para levar a barra para o alto, na sua direção.', 'Assim como indicado no exercício com halteres de mão, faça de 12 a 15 repetições antes de fazer uma pausa.', 'Agora, assim como fizera no exercício de rosca com halteres de mão, gire os braços e faça o exercício na outra posição.', 'Use instrumentos com cabos de maior circunferência.', 'Faça os exercícios usando a posição martelo sempre que possível.', 'Use alicates para punho e antebraço quando não puder ir à academia.', 'Faça dead hangs na barra-fixa.', 'Intercale levantamentos e dead hangs.', 'Faça flexões se apoiando nos dedos e pulsos.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Tomar Creatina', 'Geral', 'Geral', 'Geral', '/assets/exercises/tomar-creatina-wikihow.jpg', ARRAY['Escolha uma creatina em pó.', 'Decida se você quer “carregar” ou basear sua dosagem em relação ao seu peso.', 'Tome creatina sempre nos mesmos horários.', 'Meça 5 gramas de pó de creatina.', 'Misture o pó com um litro de água.', 'Beba a creatina imediatamente.', 'Tome 4 doses por dia durante os primeiros 5 dias.', 'Passe a tomar de 2 a 3 doses diárias.', 'Calcule sua dosagem para a primeira semana.', 'Calcule sua dose para a segunda semana.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Estabilizar a Base de um Saco de Pancada', 'Geral', 'Geral', 'Geral', '/assets/exercises/estabilizar-a-base-de-um-saco-de-pancada-wikihow.jpg', ARRAY['Preencha o suporte do saco de pancada com areia.', 'Coloque três anilhas em cada ponta da base.', 'Coloque três ou quatro sacos de areia em volta da base do saco de pancada.', 'Use tijolos ou blocos de concreto.', 'Compre uma base pesada ou com pernas mais longas.', 'Coloque tatames de espuma debaixo da base para impedir que ela escorregue.', 'Coloque o saco de pancada perto de uma parede ou um canto.', 'Instale um peso suspenso no saco de pancada.', 'Pendure o saco de pancada de uma mola grossa.', 'Aprenda a usar as técnicas certas para socar o saco de pancada.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer a sua Primeira Barra', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-a-sua-primeira-barra-wikihow.jpg', ARRAY['Suspenda o corpo pela barra sem balançar.', 'Faça a barra assistida com um elástico de resistência.', 'Faça a barra negativa.', 'Faça a barra fixa com salto para gerar impulso.', 'Tente fazer a barra fixa parcial para aumentar a sua amplitude de movimento.', 'Treine quatro ou cinco vezes por semana.', 'Trabalhe as costas com o aparelho do puxador frente.', 'Trabalhe os braços com a rosca alternada ou direta.', 'Trabalhe as costas e os braços com a remada unilateral com haltere.', 'Faça a barra fixa invertida.', 'Trabalhe a pegada com kettlebells.', 'Segure-se na barra com as mãos alinhadas aos ombros.', 'Suspenda o corpo da barra.', 'Junte as escápulas para ativar os músculos certos.', 'Levante o corpo até passar o queixo da barra.', 'Fique com a cabeça em cima da barra por um segundo.', 'Abaixe-se até estender os braços.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fortalecer Músculos Atrofiados', 'Geral', 'Geral', 'Geral', '/assets/exercises/fortalecer-musculos-atrofiados-wikihow.jpg', ARRAY['Saiba o que significa "atrofia muscular".', 'Descubra mais sobre a atrofia por desuso, a causa mais comum do problema.', 'Entenda as causas da atrofia neurogênica.', 'Reconheça os sintomas da atrofia muscular.', 'Busque auxílio médico se achar que está sofrendo atrofia muscular.', 'Trabalhe com especialistas.', 'Lembre-se de consultar o médico ou profissional de saúde antes de aderir a programas de fortalecimento muscular.', 'Contrate um personal trainer ou fisioterapeuta.', 'Comece com exercícios fáceis e avance a exercícios mais intensos.', 'Comece com reabilitação ou exercícios na água.', 'Caminhe pela piscina.', 'Faça elevações de joelho na piscina.', 'Faça flexões na piscina.', 'Faça exercícios com pesos.', 'Aprenda a fazer o agachamento.', 'Faça o afundo.', 'Tente fazer flexões de tríceps com um banco.', 'Faça abdominais básicos.', 'Tente fazer exercícios de resistência.', 'Incorpore exercícios cardiovasculares à rotina de treinamento.', 'Aprenda a fazer alguns alongamentos específicos.', 'Consuma quantidades abundantes de proteínas.', 'Aumente seu consumo de carboidratos.', 'Consuma gorduras saudáveis, como ômega 3.', 'Entenda por que o estresse é ruim para os músculos.', 'Durma bastante.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Higienizar Equipamentos de Academia', 'Geral', 'Geral', 'Geral', '/assets/exercises/higienizar-equipamentos-de-academia-wikihow.jpg', ARRAY['Use um pano úmido para limpeza.', 'Encha um borrifador com uma solução de amônia.', 'Faça uma mistura de vinagre com detergente.', 'Evite produtos de limpeza que sejam ineficientes ou perigosos.', 'Limpe cada parte do equipamento usado.', 'Use a técnica de limpeza certa.', 'Use o aspirador de pó em equipamentos domésticos.', 'Limpe minuciosamente os colchonetes.', 'Lave sempre as mãos.', 'Não toque no seu rosto.', 'Trate cortes e arranhões.', 'Lave e higienize itens pessoais.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Malhar as Costas com Halteres', 'Geral', 'Geral', 'Geral', '/assets/exercises/malhar-as-costas-com-halteres-wikihow.jpg', ARRAY['Faça o levantamento terra.', 'Faça a remada curvada.', 'Faça a remada aberta.', 'Faça o desenvolvimento com as mãos viradas para dentro.', 'Faça o agachamento com halteres nas mãos.', 'Faça o desenvolvimento alternado sentado.', 'Faça a remada unilateral.', 'Faça o crucifixo invertido.', 'Treine o manguito rotador.', 'Use as roupas certas.', 'Comece com halteres leves.', 'Faça aquecimento antes de levantar cargas pesadas.', 'Aperfeiçoe a postura.', 'Pare quando estiver cansado.', 'Treine com um amigo.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Malhar o Abdômen Usando Halteres', 'Geral', 'Geral', 'Geral', '/assets/exercises/malhar-o-abdomen-usando-halteres-wikihow.jpg', ARRAY['Use uma carga adequada.', 'Faça um bom aquecimento antes de começar.', 'Deixe a coluna reta.', 'Use toda a sua amplitude de movimento.', 'Faça de 8 a 12 repetições de cada exercício.', 'Descanse por um minuto entre cada série.', 'Lembre-se de respirar.', 'Faça um bom alongamento depois do treino.', 'Ajoelhe-se com uma perna e levante os halteres.', 'Faça a elevação alternada.', 'Faça a elevação unilateral.', 'Faça o fly e a elevação de perna.', 'Faça o exercício do inseto morto com halteres.', 'Faça exercícios unilaterais para trabalhar mais o abdômen.', 'Faça o agachamento sumô com um haltere.', 'Faça o crunch.', 'Faça flexões com um haltere suspenso.', 'Faça a postura do cachorro com dois apoios.', 'Faça a postura da cobra.', 'Faça o exercício do Superman.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('13 Formas de Treinar Como um Running Back', 'Geral', 'Geral', 'Geral', '/assets/exercises/13-formas-de-treinar-como-um-running-back-wikihow.jpg', ARRAY['Dê um salto após fazer um agachamento sem peso.', 'Apoie um pé em um banco e faça o agachamento para desenvolver o equilíbrio e a força.', 'Arraste um pneu com a força do corpo para desenvolver a velocidade e a força das pernas.', 'Faça séries de supino para fortalecer o tronco.', 'Faça flexões com impulso para fortalecer o tronco ainda mais.', 'Corra entre as linhas de um campo de futebol ou quadra de basquete para melhorar sua velocidade.', 'Pratique o drible a cada três passos.', 'Corra na diagonal entre cones para treinar a troca de direção.', 'Percorra uma escada horizontal alternando entre pisar dentro e fora dela.', 'Corra na diagonal pelos intervalos entre as barras horizontais da escada de agilidade.', 'Percorra a escada com o corpo virado de lado.', 'Peça para outra pessoa tentar tomar a bola de você.', 'Pegue a bola e corra com ela entre sacos para melhorar sua concentração.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Usar o Aparelho de Elevação de Quadril na Academia', 'Geral', 'Geral', 'Geral', '/assets/exercises/usar-o-aparelho-de-elevacao-de-quadril-na-academia-wikihow.jpg', ARRAY['Coloque anilhas nas barras do aparelho.', 'Prenda a alça ou barra de apoio por cima dos seus quadris.', 'Apoie as costas e os ombros no encosto.', 'Coloque os pés no encosto.', 'Levante os quadris para tirar as anilhas do apoio.', 'Solte a trava de segurança para aumentar a amplitude de movimento.', 'Abaixe os quadris até eles formarem 90º em relação ao seu corpo.', 'Levante os quadris para terminar a primeira repetição.', 'Faça de uma a três séries de seis a 12 repetições cada.', 'Ative a trava de segurança quando você terminar o exercício.', 'Coloque o pino na carga que você quer usar.', 'Abaixe o encosto dos pés para trabalhar os quadríceps e glúteos.', 'Levante o encosto dos pés para trabalhar os isquiotibiais e a lombar.', 'Abaixe a barra acolchoada até a menor altura possível.', 'Faça força no encosto das costas usando os ombros.', 'Apoie os pés no encosto da base do aparelho.', 'Levante os quadris do assento até eles encostarem na barra acolchoada.', 'Abaixe os quadris até formar 90º entre as coxas e as costas.', 'Volte os quadris à posição inicial para terminar a repetição.', 'Tente fazer três ou quatro séries de 20 a 25 repetições cada.', 'Levante a barra acolchoada e saia do aparelho.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Usar os Equipamentos da Academia', 'Geral', 'Geral', 'Geral', '/assets/exercises/usar-os-equipamentos-da-academia-wikihow.jpg', ARRAY['Repetições e séries:', 'Puxador:', 'Remada sentada:', 'Supino vertical:', 'Graviton:', 'Leg press:', 'Extensor de perna:', 'Repetições, séries e sessões:', 'Supino:', 'Agachamento:', 'Rosca bíceps:', 'Barra paralela:', 'Remada curvada:', 'Elevação lateral com halteres:', 'Frequência de treino:', 'Esteira:', 'Simulador de escada:', 'Elíptico:', 'Comece com calma se você tem algum problema de saúde ou não possui experiência.', 'Observe uma pessoa experiente treinar antes de usar qualquer aparelho novo.', 'Veja se os aparelhos da academia apresentam sinais de desgastes ou danos.', 'Desinfete todo aparelho antes e depois de usar.', 'Ajuste o aparelho ao seu corpo seguindo as instruções.', 'Comece com cargas mais leves e aperfeiçoe a técnica.', 'Faça movimentos controlados e lentos.', 'Faça exercícios na frente do espelho para controlar a técnica.', 'Preste atenção ao seu corpo antes, durante e depois do treino.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Melhorar Seus Reflexos', 'Geral', 'Geral', 'Geral', '/assets/exercises/melhorar-seus-reflexos-wikihow.jpg', ARRAY['Melhore a visão periférica.', 'Jogue videogames.', 'Faça hipnose.', 'Pratique a consciência plena.', 'Pratique pegar uma bola de borracha, ou "bola de reação".', 'Jogue o jogo da bugalha (também chamado de "cinco-marias").', 'Pratique queimada (ou "carimbada") com um amigo.', 'Jogue tênis de mesa.', 'Escolha um esporte e pratique-o regularmente.', 'Faça uma trilha na natureza.', 'Alimente-se de forma saudável.', 'Durma o suficiente.', 'Suplemente a alimentação.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Malhar em Casa', 'Geral', 'Geral', 'Geral', '/assets/exercises/malhar-em-casa-wikihow.jpg', ARRAY['Defina um horário para treinar todos os dias.', 'Tente fazer pelo menos 150 minutos de exercícios aeróbicos moderados por semana.', 'Faça musculação pelo menos duas vezes por semana.', 'Incorpore alongamentos ao treino para trabalhar a flexibilidade.', 'Faça aquecimento antes e alongue os músculos depois do treino.', 'Tome bastante água.', 'Treine em um espaço seguro e confortável de casa.', 'Use roupas confortáveis e arejadas.', 'Tente cumprir desafios com o treino.', 'Aqueça os músculos por cinco ou seis minutos com movimentos leves.', 'Faça duas séries de 15 a 24 repetições do agachamento com salto.', 'Faça duas séries do exercício João bobo.', 'Faça o agachamento para trabalhar os quadris e as pernas.', 'Faça duas séries de passadas para trás alternadas.', 'Faça alguns burpees.', 'Termine o treino com alguns alongamentos leves.', 'Se possível, faça alguns exercícios fora de casa.', 'Veja vídeos de aquecimento simples de acompanhar na internet.', 'Trabalhe os braços e os ombros com flexões.', 'Trabalhe os ombros e as costas com a elevação de membros alternada no chão.', 'Trabalhe o núcleo do corpo com a prancha.', 'Trabalhe os glúteos e o núcleo do corpo com a ponte borboleta.', 'Trabalhe as pernas e o bumbum com o afundo.', 'Faça a elevação de panturrilha.', 'Use garrafas PET como cargas.', 'Veja vídeos de musculação para ter motivação.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fortalecer os seus Tornozelos', 'Geral', 'Geral', 'Geral', '/assets/exercises/fortalecer-os-seus-tornozelos-wikihow.jpg', ARRAY['Gire os tornozelos.', 'Forme o alfabeto com os pés para melhorar a sua amplitude de movimento.', 'Levante os dedos dos pés.', 'Faça círculos com os tornozelos.', 'Use um elástico de resistência.', 'Faça o levantamento de tornozelo com carga.', 'Apoie o peso do corpo nos dedos dos pés.', 'Faça a elevação de panturrilha com o peso do corpo.', 'Faça o agachamento nas pontas dos pés.', 'Apoie o corpo em um pé só.', 'Faça o agachamento com uma prancha de equilíbrio.', 'Toque os dedos dos pés com a mão.', 'Mexa os dedos para cima e para baixo.', 'Flexione os dedos dos pés.', 'Alongue as panturrilhas.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fortalecer os Músculos do Pescoço', 'Geral', 'Geral', 'Geral', '/assets/exercises/fortalecer-os-musculos-do-pescoco-wikihow.jpg', ARRAY['Mexa os ombros em círculos para relaxar.', 'Toque o peito com o queixo para alongar a nuca.', 'Incline a cabeça para trás para alongar a parte dianteira do pescoço.', 'Vire a cabeça para o lado até onde conseguir por alguns segundos.', 'Aproxime a orelha do ombro para alongar o pescoço do lado.', 'Faça o alongamento da asa para relaxar os lados do pescoço.', 'Use o batente de uma porta para alongar o músculo levantador da escápula.', 'Force a cabeça contra a resistência em todas as direções.', 'Deite-se de costas e aproxime o queixo do peito.', 'Deite-se de costas, levante a cabeça e olhe para o lado.', 'Faça o encolhimento com halteres.', 'Faça a postura da roda para fortalecer o pescoço.', 'Faça a postura do cachorro olhando para baixo.', 'Faça a prancha quando o seu pescoço estiver mais forte.', 'Comece com cargas mais leves e menos repetições.', 'Faça alongamento antes e depois de treinar os músculos do pescoço.', 'Não use o ímpeto ou o impulso para fazer as repetições.', 'Faça os exercícios devagar e com cuidado.', 'Separe pelo menos dois dias de descanso entre os treinos.', 'Consulte um médico se você sente dores frequentes ou rigidez no pescoço.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Modelar o Abdômen Inferior', 'Geral', 'Geral', 'Geral', '/assets/exercises/modelar-o-abdomen-inferior-wikihow.jpg', ARRAY['Deite-se de costas e flexione os joelhos.', 'Levante as pernas até os joelhos tocarem o peito.', 'Levante os quadris e a lombar do chão.', 'Pouse os quadris no chão com calma.', 'Faça três séries de 12 crunches.', 'Deite-se de costas, com os joelhos flexionados e os pés apoiados no chão.', 'Levante os joelhos até as coxas ficarem em 90° em relação aos quadris.', 'Levante o tronco, aproxime o joelho direito do peito e estique a perna esquerda.', 'Gire o tronco para aproximar o cotovelo esquerdo do joelho direito.', 'Estique a perna direita, flexione o joelho esquerdo e gire o tronco para a esquerda.', 'Faça duas séries de dez repetições de cada lado.', 'Deite-se de costas com as pernas esticadas.', 'Levante as pernas aos poucos até elas ficarem em 90° em relação ao chão.', 'Abaixe as pernas aos poucos até elas quase tocarem o chão.', 'Faça três séries de 15 repetições.', 'Aumente a variedade do treino com os flutter kicks.', 'Consulte um médico antes de adotar um novo treino.', 'Faça aquecimento por cinco a dez minutos antes de treinar.', 'Faça os exercícios abdominais de três a cinco vezes por semana.', 'Concentre-se em trabalhar o abdômen inferior quando treinar.', 'Faça o alongamento da ponte depois do treino.', 'Incorpore exercícios intervalados ao treino para queimar as gorduras.', 'Limite a ingestão de açúcares, gorduras e carboidratos simples.', 'Consuma frutas, verduras, legumes e cereais integrais.', 'Consuma produtos de fontes de proteínas magras, em vez de carnes muito gordurosas.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer uma Abertura de Pernas', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-uma-abertura-de-pernas-wikihow.jpg', ARRAY['Use roupas apropriadas.', 'Faça um aquecimento.', 'Alongue-se.', 'Fique na posição correta.', 'Comece a abaixar o corpo.', 'Continue com cuidado até chegar ao chão.', 'Mantenha a posição.', 'Tenha paciência.', 'Depois de conseguir dominar a técnica de fazer aberturas, experimente fazer a escala extra.', 'Saiba quais músculos terá que alongar.', 'Alongue os posteriores das coxas contra uma parede.', 'Alongue-se com um agachamento unilateral.', 'Alongue-se sentado no chão com as pernas abertas.', 'Borboleta.', 'Alongue os quadríceps.', 'Alongue as panturrilhas.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer um Agachamento Unilateral', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-um-agachamento-unilateral-wikihow.jpg', ARRAY['Sente-se em um banco, uma cadeira ou caixa bem espaçada.', 'Estenda os braços à sua frente.', 'Coloque um pé no chão e flexione o joelho.', 'Estenda a outra perna à sua frente.', 'Faça força com o calcanhar e tente se levantar.', 'Sente-se de novo aos poucos.', 'Use um poste ou o batente de uma porta com espaço em volta.', 'Segure a porta com as duas mãos na altura do ombro.', 'Estenda um pé para além do batente.', 'Flexione o joelho e abaixe-se aos poucos até se sentar no ar.', 'Faça força com o pé no chão para se levantar.', 'Estenda os dois braços à sua frente.', 'Estenda uma das pernas à sua frente.', 'Flexione o joelho e abaixe-se aos poucos até se sentar no ar.', 'Faça força com o pé no chão para se levantar.', 'Determine antes se você consegue fazer o agachamento livre.', 'Não faça o exercício se você tiver qualquer lesão no joelho, nas costas, nos quadris ou no tornozelo.', 'Consulte um médico antes de adotar uma nova rotina de exercícios.', 'Treine até conseguir fazer o agachamento unilateral.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer Levantamento de Pernas', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-levantamento-de-pernas-wikihow.jpg', ARRAY['Deite-se de costas, com as pernas esticadas à sua frente.', 'Flexione os joelhos e levante as pernas.', 'Levante as pernas até os seus pés apontarem para o teto.', 'Abaixe as pernas aos poucos.', 'Diminua a velocidade se você achar o exercício fácil demais.', 'Faça três séries de 10-20 repetições.', 'Deite-se no chão.', 'Coloque uma bola entre os pés e levante as pernas.', 'Abaixe as pernas bem devagar.', 'Faça três séries de 5-10 repetições com a bola.', 'Aumente a intensidade do exercício.', 'Suspenda o corpo de uma barra pelas mãos.', 'Levante as pernas até elas ficarem perpendiculares ao seu corpo.', 'Abaixe as pernas aos poucos.', 'Faça três séries de 10-20 repetições.', 'Se necessário, diminua a dificuldade do exercício.', 'Deite-se de lado, com a cabeça apoiada na mão que está acima do cotovelo.', 'Levante a perna de cima aos poucos em pelo menos 30-60 centímetros.', 'Abaixe a perna aos poucos.', 'Faça 15 repetições de cada lado.']);
