INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Começar a Praticar Corridas', 'Geral', 'Geral', 'Geral', '/assets/exercises/comecar-a-praticar-corridas-wikihow.jpg', ARRAY['Escolha um par confortável de tênis de corrida.', 'Compre um novo par de tênis a cada 560 a 800 km percorridos.', 'Use roupas adequadas para o tempo.', 'Leve uma garrafa d''água.', 'Guarde os seus acessórios em um cinto ou uma pochete.', 'Comece a correr em um terreno plano e nivelado.', 'Corra em um local iluminado e que você conhece bem.', 'Corra em terrenos cobertos ou na esteira quando o tempo estiver fechado.', 'Planeje e monitore a corrida com um aplicativo de celular.', 'Faça uma refeição rica em proteínas de duas a quatro horas antes de correr.', 'Comece caminhando e passe a correr aos poucos.', 'Faça um bom aquecimento de cinco a dez minutos antes de correr.', 'Alterne entre correr e caminhar no início.', 'Adote a postura certa ao correr.', 'Respire normalmente durante a corrida.', 'Hidrate-se o tempo todo durante a corrida.', 'Caminhe e alongue o corpo depois de correr para relaxar.', 'Reserve horários fixos para correr.', 'Aumente o tempo e a distância da corrida gradualmente.', 'Defina metas específicas.', 'Varie no treino para deixar tudo mais interessante.', 'Convide alguém para correr com você.']);
