INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Levantar Pesos Corretamente', 'Geral', 'Geral', 'Geral', '/assets/exercises/levantar-pesos-corretamente-wikihow.jpg', ARRAY['Sempre faça aquecimento antes de começar o treino.', 'com movimentos dinâmicos (não estáticos) antes do treino.', 'Escolha a carga correta.', 'Determine o número ideal de repetições — e atenha-se a ele.', 'Faça todo o movimento antes de travar as articulações.', 'Fique atento ao ritmo das repetições.', 'Respire.', 'Descanse entre as repetições e os exercícios.', 'Peça ajuda a um professor sempre que for fazer exercícios perigosos.', 'Faça alongamentos estáticos após o treino para levar o corpo de volta ao normal.', 'Treine o peitoral', 'Treine as costas', 'Faça agachamentos.', 'Varie o seu treino.', 'Aumente a carga dos pesos gradualmente.', 'Continue fazendo séries em pirâmide e varie seus períodos de descanso.', 'Só treine algumas vezes por semana.', 'Aqueça o corpo depois do alongamento final.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Ganhar Músculos e Continuar Magrinho', 'Geral', 'Geral', 'Geral', '/assets/exercises/ganhar-musculos-e-continuar-magrinho-wikihow.jpg', ARRAY['O corpo transforma os carboidratos em energia, que por sua vez fica armazenada nos músculos.', 'As proteínas servem para dar uma energia mais duradoura ao corpo.', 'Consuma gorduras monossaturadas, que contribuem com a produção de hormônios que geram músculos.', 'Incorpore 500 calorias a mais à sua alimentação.', 'Escolha produtos ricos em proteínas e carboidratos de digestão rápida.', 'Coma algo para reparar os músculos e armazenar energia assim que você terminar de treinar.', 'Tente fazer musculação cerca de quatro vezes por semana.', 'Tire um dia a cada três ou quatro para descansar e recuperar os músculos.', 'Faça um máximo de 30 minutos de exercícios aeróbicos para não queimar tantas calorias.', 'Pense em formas de desenvolver músculos até quando você não estiver treinando!']);
