INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer um Burpee', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-um-burpee-wikihow.jpg', ARRAY['Fique de pé, com os pés alinhados aos quadris.', 'Flexione os quadris e os joelhos e agache o corpo.', 'Coloque as palmas no chão à sua frente.', 'Jogue os pés para trás e faça a prancha.', 'Abaixe o corpo até o chão.', 'Faça força com os braços e dê um pulo só com os pés para frente.', 'Pule para cima para terminar o movimento.', 'Faça 15 repetições para terminar a primeira série.', 'Fique de pé, com os pés alinhados aos quadris.', 'Agache o corpo e toque o chão com as mãos.', 'Mexa os pés até adotar a posição da flexão.', 'Aproxime os pés do peitoral e faça força com o corpo para se levantar.', 'Faça uma flexão quando você abaixar o corpo até o chão.', 'Levante peso quando você pular ou volte devagar à posição inicial.', 'Dê um salto no fim do burpee.', 'Faça o burpee com uma perna só.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer um Abdominal Canivete', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-um-abdominal-canivete-wikihow.jpg', ARRAY['Deite-se no chão e estenda os braços e as pernas.', 'Respire fundo antes de começar.', 'Expire, contraia o abdômen e estenda os braços e as pernas.', 'Fique na posição erguida por cerca de três segundos.', 'Inspire enquanto abaixa os braços e as pernas.', 'Faça duas ou três séries de dez a 12 repetições cada.', 'Comece com o tronco e as pernas elevados de leve.', 'Faça o abdominal canivete lateral para trabalhar os oblíquos.', 'Tente fazer o crunch canivete com uma bola suíça.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer o Stomach Vacuum (Exercício Abdominal)', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-o-stomach-vacuum-exercicio-abdominal-wikihow.jpg', ARRAY['Fique de pé, com os pés na largura dos ombros.', 'Inspire lentamente pelo nariz.', 'Expire pela boca até esvaziar os pulmões.', 'Afunde o umbigo o máximo que conseguir.', 'Fique na posição por aproximadamente 20 segundos se for continuar fazendo o exercício.', 'Repita o exercício inspirando enquanto relaxa o abdome.', 'Repita o exercício cinco vezes antes de fazer um intervalo.', 'Faça o exercício de pé para manter a postura correta.', 'Faça o exercício sentado para facilitar.', 'Deite-se de costas para uma respiração controlada.', 'Ajoelhe-se no chão para uma maior estabilidade.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer o Exercício da Hiperextensão em Casa', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-o-exercicio-da-hiperextensao-em-casa-wikihow.jpg', ARRAY['Deite-se de bruços em um banco de exercício reto.', 'Deslize o corpo banco acima até o seu tronco ficar suspenso.', 'Dobre o tronco para baixo até a sua cabeça quase encostar no chão.', 'Flexione as costas para levantar o tronco até onde você conseguir.', 'Abaixe o corpo até a posição inicial aos poucos.', 'Complete uma ou mais séries de 15 a 20 repetições do exercício.', 'Ajoelhe-se na frente de uma parede e atrás de uma bola de ginástica cheia.', 'Deite-se de bruços na bola.', 'Aperte os pés contra a parede para se estabilizar.', 'Coloque as mãos atrás da cabeça.', 'Levante o tronco até você alinhar a coluna.', 'Abaixe o tronco para completar a primeira repetição.', 'Complete uma ou mais séries de 15 a 20 repetições do exercício.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer Mergulho (Exercício)', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-mergulho-exercicio-wikihow.jpg', ARRAY['Adote a posição certa, com o banco atrás de você.', 'Contraia o abdômen e abaixe o corpo do lado do banco.', 'Deixe a cabeça e o tronco em linha reta.', 'Fique na posição mais baixa por um ou dois segundos e, em seguida, volte ao início.', 'Levante e abaixe o corpo algumas vezes, mas sem se sentar no banco.', 'Adote a posição inicial, com as mãos nas barras paralelas.', 'Abaixe o corpo com a força dos braços, mantendo o tronco e a cabeça em linha reta.', 'Faça força para voltar à posição inicial.', 'Continue levantando e abaixando o corpo até terminar a série.', 'Incline o tronco um pouco para frente para trabalhar mais o peitoral.', 'Ajuste o equipamento de acordo com a sua resistência.', 'Suba na plataforma de apoio.', 'Flexione os cotovelos para abaixar o corpo devagar.', 'Faça força para voltar à posição inicial.', 'Repita o movimento de oito a dez vezes para terminar a primeira série.', 'Desça da máquina com cuidado.', 'Ajuste a distância das barras e fique de olho nas suas mãos.', 'Encontre a posição perfeita para os braços.', 'Projete o peito e a cabeça para frente.', 'Coloque as pernas na posição certa.', 'Inspire e expire na altura máxima do exercício.']);
