INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Testar a Força do Abdômen', 'Geral', 'Geral', 'Geral', '/assets/exercises/testar-a-forca-do-abdomen-wikihow.jpg', ARRAY['Peça ajuda a um amigo ou familiar.', 'Deite-se de costas e dobre os joelhos.', 'Comece a marcar o tempo e faça o maior número possível de repetições em 30 segundos.', 'Compare os resultados do seu teste à média comum para a sua faixa etária.', 'Comece colocando as mãos e os joelhos na posição certa.', 'Marque quanto tempo você consegue ficar nessa posição no relógio.', 'Estenda as pernas e adote a posição da prancha.', 'Fique nessa posição pelo tempo que você conseguir sem perder a forma.', 'Vá à academia fazer o teste.', 'Ajuste a sua forma com uma barra.', 'Coloque a carga mais pesada que você conseguir levantar na barra.', 'Levante a barra do chão e estabilize o peso.', 'Ande com a carga por pelo menos 30 segundos.', 'Peça para um amigo ou familiar marcar o tempo para você.', 'Comece em uma versão modificada da prancha.', 'Estenda cada membro individual por 15 segundos cada.', 'Estenda dois membros alternados por 15 segundos.', 'Faça exercícios de respiração profunda para trabalhar o abdômen.', 'Faça a prancha básica.', 'Faça o abdominal com perdigueiro para desenvolver o equilíbrio e a estabilidade.', 'Faça a ponte para fortalecer os flexores do quadril e os glúteos.', 'Comece a praticar yoga ou tai chi chuan para desenvolver o equilíbrio e a flexibilidade.', 'Repita os testes deste artigo uma vez por mês.']);
