INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Tirar Medidas de Músculos para Praticar Fisiculturismo', 'Geral', 'Geral', 'Geral', '/assets/exercises/tirar-medidas-de-musculos-para-praticar-fisiculturismo-wikihow.jpg', ARRAY['Tire as medidas antes de treinar para gerar resultados confiáveis.', 'Escolha entre flexionar e relaxar os músculos na hora de tirar as medidas.', 'Coloque a fita métrica bem rente à pele na hora de tirar as medidas.', 'Peça ajuda a alguém sempre que possível.', 'Levante o braço até ele ficar paralelo ao chão.', 'Feche o punho e dobre o braço para cima, na direção da cabeça.', 'Passe a fita métrica em volta da parte mais grossa do bíceps.', 'Corrija a posição da fita métrica e tire a medida.', 'Estenda o braço para frente até ele se alinhar ao ombro.', 'Passe a fita métrica pela parte mais grossa do braço.', 'Feche a fita métrica na vertical para tirar a medida.', 'Estenda o antebraço para frente e feche o punho.', 'Passe a fita métrica pela parte mais grossa do antebraço.', 'Alinhe a fita métrica e anote as medidas.', 'Estenda o antebraço para frente, abra o punho e afaste os dedos.', 'Coloque a fita métrica debaixo dos ossos do pulso.', 'Tire a medida com a fita métrica debaixo dos ossos.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Ter um Espaço Entre as Coxas', 'Geral', 'Geral', 'Geral', '/assets/exercises/ter-um-espaco-entre-as-coxas-wikihow.jpg', ARRAY['Entenda que a maioria das pessoas não consegue ter o espaço entre as coxas.', 'Crie expectativas realistas.', 'Não fique obcecada.', 'Peça ajuda se você achar que está começando a prejudicar a sua saúde.', 'Se você quiser mesmo o espaço, combine uma alimentação saudável e a prática de exercícios.', 'Pare de comer porcaria.', 'Ingira mais fibras.', 'Inclua superalimentos na sua alimentação.', 'Não coma demais.', 'Faça o alongamento borboleta.', 'Faça o levantamento de perna de pilates.', 'Aperte uma almofada entre as coxas.', 'Faça exercícios aeróbicos.', 'Evite praticar exercícios que engrossem as pernas.', 'Use cintas e outros acessórios.', 'Passe um creme anticelulite.', 'Passe uma escova no corpo.', 'Use um bronzeador para criar a ilusão de ter pernas torneadas.', 'Aprenda as técnicas para dar a ilusão do espaço para quando você for tirar fotos.', 'Estique bem as pernas.', 'Projete o bumbum para trás.', 'Incline o corpo para frente e afaste os calcanhares.', 'Tire a foto.', 'Espere passar pela puberdade.', 'Entenda quando é hora de consultar um médico.']);
