INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Ter Pernas Gostosas Rapidamente', 'Geral', 'Geral', 'Geral', '/assets/exercises/ter-pernas-gostosas-rapidamente-wikihow.jpg', ARRAY['Faça três séries de 15 a 20 agachamentos para trabalhar as coxas e os glúteos.', 'Faça três séries de 15 a 20 afundos com cada perna.', 'Faça três séries de 15 a 20 elevações de panturrilha.', 'Faça três séries de oito a 12 agachamentos na parede para trabalhar as coxas e os glúteos.', 'Faça um bom alongamento depois do treino para aumentar a sua flexibilidade e evitar lesões.', 'Treine as pernas três vezes por semana para ver resultados rápidos.', 'Faça o agachamento com halteres ou uma barra.', 'Faça o afundo com halteres.', 'Faça a elevação da panturrilha com halteres.', 'Tome pelo menos 2,5 L de água por dia para se hidratar.', 'Passe um creme nas pernas todos os dias para deixar a pele macia.', 'Passe um esfoliante de açúcar nas pernas uma ou duas vezes por semana.', 'Passe um autobronzeador', 'Use meias-calças de cores claras para gerar um efeito instantâneo.', 'Ande de salto para alongar as pernas.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('se Tornar um Personal Trainer', 'Geral', 'Geral', 'Geral', '/assets/exercises/se-tornar-um-personal-trainer-wikihow.jpg', ARRAY['Forme-se no ensino médio.', 'Obtenha certificados de RCP e DEA.', 'Forme-se em educação física e registre-se no CREF para poder atuar na área.', 'Faça um curso breve de personal training para focar bem na nova função.', 'Faça um curso focado em personal training para entrar de cabeça na indústria.', 'Estude os diversos campos científicos relacionados ao treinamento físico.', 'Equilibre a teoria com treinamento físico.', 'Estude sobre empreendedorismo para ter sucesso como profissional no meio do personal training.', 'Desenvolva habilidades de comunicação e liderança empáticas.', 'Defina uma rotina de bem-estar e aptidão física para si próprio.', 'Procure por um programa de certificação CPT de boa reputação.', 'Inscreva-se para o exame de certificação e prepare-se de acordo com os requisitos.', 'Participe do exame de certificação.', 'Procure por trabalhos em academias.', 'Monte uma cartela de clientes.', 'Abra seu próprio negócio.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Se Exercitar', 'Geral', 'Geral', 'Geral', '/assets/exercises/se-exercitar-wikihow.jpg', ARRAY['Adapte a rotina de exercícios ao seu nível de experiência.', 'Faça aquecimento por 5-10 minutos antes de começar a treinar.', 'Tente fazer 30 minutos de exercícios aeróbicos por dia.', 'Faça musculação pelo menos duas vezes por semana.', 'Varie no treino para deixar as coisas mais interessantes.', 'Caminhe por 5-10 minutos e faça alongamento depois do treino para relaxar os músculos.', 'Faça uma caminhada ou corrida leve todos os dias.', 'por 5-15 minutos.', 'por 5-15 minutos.', 'Ande de bicicleta.', 'um pouco na piscina da academia ou de um clube local.', 'Aperte o passo da corrida quando você se acostumar.', 'Faça o treino intervalado para aumentar a intensidade.', 'para trabalhar os braços e o peito.', 'Tente fazer a prancha por 30-45 segundos.', 'Faça abdominais.', 'Faça a ponte para trabalhar os glúteos e o abdômen.', 'Faça o agachamento para trabalhar as pernas.', 'Faça o burpee para trabalhar o corpo inteiro.', 'Invista em alguns pesos ou matricule-se em uma academia.', 'depois de aquecer os músculos.', 'Comece a fazer yoga.', 'Faça pilates.', 'Faça aulas de dança para se manter ativo.', 'Integre o tai chi chuan à sua rotina de exercícios.', 'Reserve um tempinho a cada dia para as atividades físicas.', 'Não fique tanto tempo sentado.', 'Troque o elevador pelas escadas.', 'Vá andando ou de bicicleta para os seus compromissos (em vez de carro).', 'Consulte um médico antes de começar a praticar exercícios.', 'Beba bastante água antes, durante e depois dos exercícios.', 'Use roupas que sejam adequadas para as atividades.', 'Use tênis de academia, que deem o devido suporte aos pés.', 'Pare de treinar se você sentir dor.']);
