INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Obter Coxas mais Magras', 'Geral', 'Geral', 'Geral', '/assets/exercises/obter-coxas-mais-magras-wikihow.jpg', ARRAY['Entenda que é impossível perder peso em áreas específicas do corpo.', 'Diminua a ingestão e aumente a queima de calorias.', 'Ingira mais proteínas magras, vegetais, cereais integrais e frutas.', 'Limite a ingestão de alimentos processados e doces, que contêm muitas calorias vazias.', 'Não passe fome.', 'Faça pelo menos 150 minutos de exercícios aeróbicos moderados ou 75 minutos de exercícios mais intensos por semana.', 'Faça uma caminhada leve de vez em quando.', 'Incorpore lances de escadas ao seu treino.', 'Incorpore um pouco de dança ao seu treino.', 'Pratique esportes recreativos.', 'Faça séries de HIIT para aumentar a intensidade do treino.', 'para tonificar os músculos.', 'Faça o agachamento para trabalhar a força das pernas e dos glúteos.', 'Faça o agachamento contra a parede.', 'Faça a adução de perna para trabalhar a parte interna das coxas.', 'Faça a abdução de perna para trabalhar a parte externa das coxas.', 'Faça o abdominal tesoura para trabalhar as duas pernas ao mesmo tempo.']);
