INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Corrigir um Desequilíbrio Muscular Entre os Seus Bíceps', 'Geral', 'Geral', 'Geral', '/assets/exercises/corrigir-um-desequilibrio-muscular-entre-os-seus-biceps-wikihow.jpg', ARRAY['Faça exercícios unilaterais para desenvolver o equilíbrio.', 'Comece treinando o seu braço mais fraco.', 'Faça o mesmo número de repetições dos dois lados.', 'Escolha um nível de peso adequado para o seu braço mais fraco.', 'Treine os tríceps para evitar desequilíbrios mais sérios.', 'Lembre-se de fazer exercícios bilaterais.', 'Consulte um fisioterapeuta se você tiver um desequilíbrio sério nos bíceps.', 'Preste atenção à sua forma durante qualquer exercício.', 'Estude as suas fotos ou dê uma boa olhada no espelho em busca de desequilíbrios óbvios.', 'Faça um teste com exercícios unilaterais.', 'Faça uma avaliação biométrica para identificar desequilíbrios mais sutis.', 'Verifique se você tem uma amplitude de movimento limitada nos tríceps.']);
