INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer Desenvolvimento Militar', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-desenvolvimento-militar-wikihow.jpg', ARRAY['Faça o desenvolvimento militar para trabalhar os ombros e os braços.', 'Escolha uma barra que você consiga levantar sem dificuldade até os ombros.', 'Apoie a barra em um rack que tenha a altura dos seus ombros.', 'Segure a barra com as mãos um pouco além dos ombros, com as palmas viradas para frente e para cima.', 'Alinhe os pés aos ombros.', 'Expire na hora de levantar a barra acima da cabeça.', 'Inspire na hora de abaixar a barra até a clavícula.', 'Levante a barra de novo para terminar a primeira repetição.', 'Faça o desenvolvimento militar sentado.', 'Use halteres para isolar os ombros.', 'Vire as palmas das mãos para dentro para trabalhar regiões diferentes dos músculos.', 'Faça o desenvolvimento ajoelhado para melhorar a postura e estabilizar o abdômen.', 'Faça algumas variações do desenvolvimento para otimizar o treino.', 'Faça um teste com as mãos para não errar na hora de pegar a barra ou os halteres.', 'Coloque um pé na frente do outro para ficar mais equilibrado e confortável.', 'Faça o exercício devagar e pare com os braços esticados para otimizar os efeitos.', 'Faça exercícios isolados para desenvolver ainda mais os ombros.']);
