INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer Afundos', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-afundos-wikihow.jpg', ARRAY['Comece ficando de pé.', 'Dê um passo largo para frente com a perna direita.', 'Abaixe o corpo até o seu joelho direito ficar em 90°.', 'Projete o corpo para cima com o pé direito.', 'Repita o movimento.', 'Comece ficando de pé.', 'Dê um passo largo para trás com a perna esquerda.', 'Flexione as duas pernas em 90°.', 'Volte à posição inicial.', 'Repita o afundo inverso.', 'Comece ficando de pé.', 'Dê um passo para a direita.', 'Flexione o joelho direito.', 'Faça força no chão com o pé direito.', 'Faça o mesmo número de repetições do lado esquerdo.', 'Comece ficando de pé.', 'Tire o pé direito do chão.', 'Coloque o pé direito no chão a partir do calcanhar.', 'Gire o tronco para a direita.', 'Dê um passo à frente com a perna esquerda.', 'Coloque o pé esquerdo no chão.', 'Gire o tronco para a esquerda.', 'Continue repetindo os movimentos conforme faz o afundo para frente.', 'Reserve um período de 30 dias para fazer o desafio.', 'Faça pelo menos 100 afundos por semana.', 'Tente fazer 100 afundos por dia aos poucos.', 'Monitore o seu progresso.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer Abdominal Militar', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-abdominal-militar-wikihow.jpg', ARRAY['Deite-se de costas no chão e flexione os joelhos de leve.', 'Cruze os braços sobre o peito.', 'Levante o tronco até ele ficar vertical.', 'Abaixe as costas até tocar o chão com as escápulas.', 'Repita o exercício.', 'Faça três séries de oito a 12 repetições.', 'Aumente o número de repetições ou séries aos poucos.', 'Faça o militar várias vezes por semana.', 'Não desista até chegar onde quer.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Acabar com as Depressões nos Quadris', 'Geral', 'Geral', 'Geral', '/assets/exercises/acabar-com-as-depressoes-nos-quadris-wikihow.jpg', ARRAY['Faça a ponte para tonificar os quadris.', 'Faça o afundo para tonificar as coxas, os quadris e os glúteos.', 'Faça a elevação lateral em pé em um banco para tonificar os quadris e os glúteos.', 'Faça a prancha para tonificar o abdômen.', 'Faça abdominais com as pernas elevadas para tonificar a barriga e os quadris.', 'Faça o agachamento para tonificar o abdômen.', 'Faça o exercício do coice (ou quatro apoios).', 'Use roupas um pouco mais folgadas.', 'Escolha tecidos que não fiquem grudados no seu corpo.', 'Use blusas e casacos mais longos.', 'Compre peças com babados do tipo peplum na região da cintura.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer a Remada Curvada', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-a-remada-curvada-wikihow.jpg', ARRAY['Adote a posição certa.', 'Pegue e levante a barra.', 'Faça a remada.', 'Experimente pegadas diferentes.', 'Faça a remada curvada com halteres.', 'Faça a remada curvada unilateral.', 'Use equipamentos alternativos para treinar em casa.', 'Faça a remada curvada no Smith.', 'Faça a remada curvada em um aparelho em T.', 'Faça a remada curvada em um aparelho de remo.', 'Posicione a faixa elástica.', 'Adote a posição correta.', 'Faça a remada.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer a Flexão com Peso Sem Ajuda', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-a-flexao-com-peso-sem-ajuda-wikihow.jpg', ARRAY['Treine usando um colete de carga ajustável.', 'Faça a flexão usando um elástico de resistência.', 'Coloque uma mochila com garrafas d''água nas costas.', 'Coloque uma anilha nas costas e adote a posição da flexão.', 'Fique de quatro no colchonete.', 'Adote a posição inicial da flexão.', 'Alinhe os pés às palmas e levante os calcanhares do chão.', 'Levante o corpo do chão sem arquear as costas.', 'Abaixe o corpo devagar e sem perder a forma.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer a Flexão Aberta', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-a-flexao-aberta-wikihow.jpg', ARRAY['Fique de quatro em uma superfície estável.', 'Coloque as palmas das mãos no chão um pouco além dos ombros.', 'Levante o seu corpo e encoste no chão somente com as palmas e os dedos dos pés.', 'Forme uma linha reta da cabeça aos pés para adotar a postura da prancha.', 'Tente expandir as suas escápulas durante o exercício.', 'Abaixe o peitoral em um movimento fluido até quase encostar no chão.', 'Pare por um instante quando você abaixar o peitoral.', 'Expire devagar e volte à posição inicial.', 'Repita o processo até terminar a série.', 'Faça três ou quatro séries duas ou três vezes por semana.', 'Ajuste a distância das suas mãos entre as séries para trabalhar outros grupos musculares.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer a Elevação dos Dedos e das Panturrilhas', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-a-elevacao-dos-dedos-e-das-panturrilhas-wikihow.jpg', ARRAY['Comece fazendo a elevação sentado.', 'Passe a fazer a elevação de pé com apoio.', 'Passe a levantar os calcanhares.', 'Faça a elevação unilateral.', 'Incorpore um elástico de resistência ao treino.', 'Comece fazendo a elevação de panturrilha básica.', 'Faça a elevação de panturrilha unilateral.', 'Faça a elevação de panturrilha em um step ou outra plataforma.', 'Faça a elevação de panturrilha básica usando halteres.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Fazer a Barra Fixa sem o Aparelho', 'Geral', 'Geral', 'Geral', '/assets/exercises/fazer-a-barra-fixa-sem-o-aparelho-wikihow.jpg', ARRAY['em uma porta resistente.', 'Use as barras de um parquinho local ou uma academia a céu aberto.', 'Faça a barra em galhos grossos de árvores.', 'Faça a barra de um muro ou portão.', 'Prenda uma toalha nos dois lados da alça de uma porta.', 'Faça a barra invertida debaixo de uma mesa.', 'Coloque um cabo de metal entre duas cadeiras.', 'Faça a barra invertida em um corrimão.', 'Faça a remada curvada.', 'Faça a rosca bíceps com halteres ou a barra solta.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Exercitar os Músculos da Canela', 'Geral', 'Geral', 'Geral', '/assets/exercises/exercitar-os-musculos-da-canela-wikihow.jpg', ARRAY['Faça a elevação da canela na parede.', 'Faça a elevação de perna.', 'Simule uma caminhada.', 'Alongue a canela sentado.', 'Treine a panturrilha.', 'Contraia os dedos dos pés.', 'Alongue as panturrilhas.', 'Faça exercícios de resistência para trabalhar as canelas.', 'Caminhe com o elástico de resistência.']);
INSERT INTO public.biblioteca_exercicios (nome, body_part, target_muscle, equipment, video_url, instrucoes) VALUES ('Estalar os Quadris', 'Geral', 'Geral', 'Geral', '/assets/exercises/estalar-os-quadris-wikihow.jpg', ARRAY['Sente-se em uma cadeira confortável.', 'Coloque uma perna em cima da outra.', 'Coloque as mãos sobre o joelho da perna de cima.', 'Incline o tronco para frente até onde você conseguir.', 'Fique nessa posição por até 30 segundos.', 'Repita esse alongamento do outro lado para relaxar os quadris.', 'Fique de pé em uma área bem espaçosa.', 'Dobre os braços e junte as mãos na frente da barriga.', 'Gire o tronco para a esquerda até onde você conseguir.', 'Gire o tronco para a direita.', 'Repita o exercício duas ou três vezes.', 'Faça a postura do pombo para abrir os quadris.', 'Sente-se e alongue os flexores do quadril.', 'Sente-se e faça a mobilização dos quadris.', 'Consulte um quiroprático se você não conseguir estalar os quadris.', 'Consulte um fisioterapeuta se você sentir tensão ou dores crônicas nos quadris.', 'Consulte um médico se a tensão se transformar em dor.']);
